1	/**
2	 * Merge-completion handler.
3	 *
4	 * When the in_review poll reports `merged: true` for a task's implementation
5	 * PR, this handler:
6	 *
7	 *   1. Reads the live task state from the feature branch (idempotency guard).
8	 *   2. Checks out and syncs the feature branch on the management repo.
9	 *   3. Updates the task YAML: status → done, pr.status → merged, done log entry.
10	 *   4. Applies the auto-ready rule: scans sibling task YAMLs in the same
11	 *      feature and transitions todo → ready for any whose depends_on list is
12	 *      now fully satisfied.
13	 *   5. Commits all YAML changes (completing task + newly-ready tasks) in one
14	 *      commit and pushes to the feature branch.  On push rejection, attempts
15	 *      a fetch+rebase recovery; if the rebase has conflicts, spawns Claude to
16	 *      resolve the YAML markers.  On persistent failure, emits
17	 *      pr_merge_done_blocked and skips the workspace PR merge.
18	 *   6. Merges the management-repo PR (workspace_pr) via the GitHub REST API.
19	 *      Errors here are non-fatal — the task YAML done state is preserved.
20	 */
21	
22	import { execSync, spawnSync, spawn } from "node:child_process";
23	import { readFileSync, writeFileSync, readdirSync } from "node:fs";
24	import { join } from "node:path";
25	import { parse as parseYaml, stringify as yamlStringify } from "yaml";
26	import type { Task } from "../types/task.js";
27	import { taskYamlAbsPath, taskYamlRelPath, featuresRoot, TASKS_DIR } from "../paths.js";
28	import type { PrStatusResult, WorkspacePrRecovery } from "./check-in-review-prs.js";
29	import { parsePrUrl } from "./check-in-review-prs.js";
30	import { buildGitCommitEnv } from "../git-env.js";
31	import { tryReadTaskFromBranch } from "../task-branch-state.js";
32	import { taskBranchName } from "../paths.js";
33	
34	// ── Public types ──────────────────────────────────────────────────────────────
35	
36	export interface HandleMergedPrsOptions {
37	  /** Results from checkInReviewPrs — only those with merged === true are processed. */
38	  prResults: PrStatusResult[];
39	  /** Absolute path to the management (workspace) repo root. */
40	  workspaceRoot: string;
41	  /** GitHub owner of the management repo (for workspace PR merge call). */
42	  mgmtRepoOwner: string;
43	  /** GitHub repo name of the management repo. */
44	  mgmtRepoName: string;
45	  /** GitHub personal access token. */
46	  githubToken: string;
47	  /** GIT_AUTHOR_EMAIL for commits and log entries. */
48	  gitAuthorEmail: string;
49	  /** GIT_AUTHOR_NAME for commits. Defaults to gitAuthorEmail. */
50	  gitAuthorName: string;
51	  /** SSH private key path for git push operations. */
52	  sshKeyPath?: string;
53	  /** Structured event emitter for observability. */
54	  emit: (event: Record<string, unknown>) => void;
55	  /**
56	   * Optional override for spawning Claude to resolve YAML conflict markers.
57	   * Receives the prompt string, the workspace cwd, and the process env.
58	   * Returns true if resolution succeeded, false otherwise.
59	   */
60	  invokeClaudeForResolution?: (
61	    prompt: string,
62	    cwd: string,
63	    env: NodeJS.ProcessEnv,
64	  ) => Promise<boolean>;
65	}
66	
67	// ── Internal helpers ──────────────────────────────────────────────────────────
68	
69	/**
70	 * Call the GitHub REST API to merge a pull request.
71	 * Returns success/failure with full response details on failure.
72	 */
73	export function mergeWorkspacePrViaApi(
74	  mgmtRepoOwner: string,
75	  mgmtRepoName: string,
76	  prNumber: number,
77	  githubToken: string,
78	): { success: boolean; details: string } {
79	  const url = `https://api.github.com/repos/${mgmtRepoOwner}/${mgmtRepoName}/pulls/${prNumber}/merge`;
80	  const body = JSON.stringify({ merge_method: "squash" });
81	
82	  const result = spawnSync(
83	    "curl",
84	    [
85	      "-s", "-X", "PUT",
86	      "-H", `Authorization: token ${githubToken}`,
87	      "-H", "Accept: application/vnd.github+json",
88	      "-H", "Content-Type: application/json",
89	      "-d", body,
90	      url,
91	    ],
92	    { encoding: "utf-8", stdio: ["ignore", "pipe", "pipe"] },
93	  );
94	
95	  if (result.error) {
96	    return { success: false, details: String(result.error) };
97	  }
98	  const stdout = result.stdout ?? "";
99	  if (!stdout.trim()) {
100	    return { success: false, details: `curl returned empty response. stderr: ${result.stderr ?? ""}` };
101	  }
102	
103	  try {
104	    const data = JSON.parse(stdout) as { merged?: boolean; message?: string };
105	    if (data.merged === true) {
106	      return { success: true, details: "" };
107	    }
108	    return { success: false, details: JSON.stringify(data) };
109	  } catch {
110	    return { success: false, details: `Non-JSON response: ${stdout}` };
111	  }
112	}
113	
114	/**
115	 * Return files that currently have conflict markers via `git diff --name-only --diff-filter=U`.
116	 */
117	function listConflictedFiles(
118	  repoRoot: string,
119	  env: NodeJS.ProcessEnv,
120	): string[] {
121	  try {
122	    const output = execSync(
123	      `git -C "${repoRoot}" diff --name-only --diff-filter=U`,
124	      { env, encoding: "utf-8", stdio: ["ignore", "pipe", "pipe"] },
125	    ).trim();
126	    return output ? output.split("\n") : [];
127	  } catch {
128	    return [];
129	  }
130	}
131	
132	/**
133	 * Build a Claude prompt for resolving YAML task file conflict markers.
134	 * Instructs Claude to keep the local done/ready status and merge log arrays.
135	 */
136	function buildYamlConflictResolutionPrompt(
137	  repoRoot: string,
138	  conflictedFiles: string[],
139	): string {
140	  const fileList = conflictedFiles.map((f) => `- ${f}`).join("\n");
141	  return (
142	    `You are resolving git merge conflicts in YAML task files in the repository at ${repoRoot}.\n` +
143	    `The following files contain conflict markers (<<<<<<<, =======, >>>>>>>):\n\n` +
144	    fileList +
145	    `\n\nFor each file:\n` +
146	    `1. Read the file contents (which include conflict markers).\n` +
147	    `2. Resolve the conflict markers using these rules:\n` +
148	    `   - Keep the LOCAL (<<<<<<< HEAD) values for status, pr.status, execution fields.\n` +
149	    `   - Merge the log arrays from BOTH sides — include all entries from both HEAD and the incoming branch, sorted by the "at" timestamp.\n` +
150	    `   - For all other scalar fields, keep the LOCAL value.\n` +
151	    `3. Write the fully resolved YAML content back to disk.\n\n` +
152	    `IMPORTANT:\n` +
153	    `- Do NOT run git add or git commit — only write the resolved file contents.\n` +
154	    `- Do NOT modify any files that are not listed above.\n` +
155	    `- After writing all files, respond with a brief summary of what was resolved.`
156	  );
157	}
158	
159	/**
160	 * Default implementation: spawns Claude CLI to resolve YAML conflict markers.
161	 */
162	async function defaultInvokeClaudeForResolution(
163	  prompt: string,
164	  cwd: string,
165	  env: NodeJS.ProcessEnv,
166	): Promise<boolean> {
167	  return new Promise((resolve) => {
168	    const child = spawn(
169	      "claude",
170	      [
171	        "-p", prompt,
172	        "--max-turns", "5",
173	        "--output-format", "stream-json",
174	        "--verbose",
175	        "--dangerously-skip-permissions",
176	      ],
177	      { cwd, env, stdio: ["ignore", "pipe", "pipe"] },
178	    );
179	
180	    child.stdout.pipe(process.stdout);
181	    child.stderr.pipe(process.stderr);
182	
183	    child.on("close", (code) => resolve(code === 0));
184	    child.on("error", () => resolve(false));
185	  });
186	}
187	
188	// ── Public API ────────────────────────────────────────────────────────────────
189	
190	/**
191	 * Iterate poll results where `merged === true` and close out each task:
192	 * mark done, activate unblocked dependents, and merge the workspace PR.
193	 */
194	export async function handleMergedPrs(opts: HandleMergedPrsOptions): Promise<void> {
195	  const {
196	    prResults,
197	    workspaceRoot,
198	    mgmtRepoOwner,
199	    mgmtRepoName,
200	    githubToken,
201	    gitAuthorEmail,
202	    gitAuthorName,
203	    sshKeyPath,
204	    emit,
205	  } = opts;
206	
207	  const mergedResults = prResults.filter((r) => r.merged === true);
208	  if (mergedResults.length === 0) return;
209	
210	  const env = buildGitCommitEnv(gitAuthorEmail, gitAuthorName, sshKeyPath);
211	  const invoker = opts.invokeClaudeForResolution ?? defaultInvokeClaudeForResolution;
212	
213	  for (const result of mergedResults) {
214	    const { taskId, featureId } = result;
215	    const taskBranch = taskBranchName(featureId, taskId);
216	    const relPath = taskYamlRelPath(featureId, taskId);
217	
218	    // ── 1. Idempotency guard: read live task state from feature branch ─────────
219	    const liveTask = tryReadTaskFromBranch(workspaceRoot, taskBranch, relPath);
220	    if (!liveTask) {
221	      emit({
222	        type: "pr_merge_skip",
223	        task_id: taskId,
224	        feature_id: featureId,
225	        reason: "task_branch_not_found",
226	      });
227	      continue;
228	    }
229	
230	    if (liveTask.status !== "in_review") {
231	      emit({
232	        type: "pr_merge_skip",
233	        task_id: taskId,
234	        feature_id: featureId,
235	        reason: `task_already_${liveTask.status}`,
236	      });
237	      continue;
238	    }
239	
240	    // ── 2. Checkout and sync feature branch ───────────────────────────────────
241	    try {
242	      execSync(`git -C "${workspaceRoot}" fetch origin`, { env, stdio: "pipe" });
243	      execSync(`git -C "${workspaceRoot}" checkout "${taskBranch}"`, { env, stdio: "pipe" });
244	      execSync(`git -C "${workspaceRoot}" pull origin "${taskBranch}"`, { env, stdio: "pipe" });
245	    } catch (e) {
246	      emit({
247	        type: "pr_merge_done_blocked",
248	        task_id: taskId,
249	        feature_id: featureId,
250	        reason: "branch_sync_failed",
251	        details: String(e),
252	      });
253	      continue;
254	    }
255	
256	    // ── 3. Update task YAML on disk ───────────────────────────────────────────
257	    const now = new Date().toISOString();
258	    let task: Task;
259	    try {
260	      task = parseYaml(
261	        readFileSync(taskYamlAbsPath(workspaceRoot, featureId, taskId), "utf-8"),
262	      ) as Task;
263	    } catch (e) {
264	      emit({
265	        type: "pr_merge_done_blocked",
266	        task_id: taskId,
267	        feature_id: featureId,
268	        reason: "task_yaml_read_failed",
269	        details: String(e),
270	      });
271	      continue;
272	    }
273	
274	    // Second idempotency check after checkout (guards against races).
275	    if (task.status !== "in_review") {
276	      emit({
277	        type: "pr_merge_skip",
278	        task_id: taskId,
279	        feature_id: featureId,
280	        reason: `task_already_${task.status}_after_checkout`,
281	      });
282	      continue;
283	    }
284	
285	    task.status = "done";
286	    task.pr = { ...task.pr, status: "merged" };
287	    task.execution.last_updated_by = gitAuthorEmail;
288	    task.execution.last_updated_at = now;
289	    task.log.push({
290	      action: "done",
291	      by: gitAuthorEmail,
292	      at: now,
293	      note: "Implementation PR merged — automated close-out by pr-merge loop.",
294	    });
295	
296	    writeFileSync(
297	      taskYamlAbsPath(workspaceRoot, featureId, taskId),
298	      yamlStringify(task),
299	      "utf-8",
300	    );
301	
302	    // ── 4. Auto-ready rule: activate sibling tasks whose deps are now satisfied
303	    const allRelPaths: string[] = [relPath];
304	    const tasksDir = join(featuresRoot(workspaceRoot), featureId, TASKS_DIR);
305	
306	    let siblingFiles: string[] = [];
307	    try {
308	      siblingFiles = readdirSync(tasksDir).filter(
309	        (f) => /^T\d+\.yaml$/.test(f) && f !== `${taskId}.yaml`,
310	      );
311	    } catch { /* best-effort — skip auto-ready if tasks dir unreadable */ }
312	
313	    // Build a status map for dependency resolution.
314	    // Start with the just-completed task (now done).
315	    const taskStatusMap = new Map<string, string>([[taskId, "done"]]);
316	    for (const sibFile of siblingFiles) {
317	      try {
318	        const sibTask = parseYaml(
319	          readFileSync(join(tasksDir, sibFile), "utf-8"),
320	        ) as Task;
321	        taskStatusMap.set(sibTask.id, sibTask.status);
322	      } catch { /* skip unreadable files */ }
323	    }
324	
325	    for (const sibFile of siblingFiles) {
326	      try {
327	        const sibPath = join(tasksDir, sibFile);
328	        const sibTask = parseYaml(readFileSync(sibPath, "utf-8")) as Task;
329	
330	        // Only consider todo tasks that depend on the just-completed task.
331	        if (sibTask.status !== "todo") continue;
332	        if (!Array.isArray(sibTask.depends_on) || !sibTask.depends_on.includes(taskId)) continue;
333	
334	        // All deps must now be done.
335	        const allDepsDone = sibTask.depends_on.every(
336	          (depId) => taskStatusMap.get(depId) === "done",
337	        );
338	        if (!allDepsDone) continue;
339	
340	        const sibNow = new Date().toISOString();
341	        sibTask.status = "ready";
342	        sibTask.log.push({
343	          action: "ready",
344	          by: gitAuthorEmail,
345	          at: sibNow,
346	          note: `Task activated — dependency ${taskId} merged and marked done.`,
347	        });
348	
349	        writeFileSync(sibPath, yamlStringify(sibTask), "utf-8");
350	        allRelPaths.push(taskYamlRelPath(featureId, sibTask.id));
351	
352	        emit({
353	          type: "task_auto_readied",
354	          task_id: sibTask.id,
355	          feature_id: featureId,
356	          activated_by: taskId,
357	        });
358	      } catch { /* skip individual sibling errors */ }
359	    }
360	
361	    // ── 5. Commit + push with rebase-and-resolve on rejection ─────────────────
362	    let pushSucceeded = false;
363	
364	    try {
365	      for (const rp of allRelPaths) {
366	        execSync(`git -C "${workspaceRoot}" add "${rp}"`, { env, stdio: "pipe" });
367	      }
368	      execSync(
369	        `git -C "${workspaceRoot}" commit -m "chore(${taskId}): mark done + activate unblocked tasks"`,
370	        { env, stdio: "pipe" },
371	      );
372	    } catch (e) {
373	      emit({
374	        type: "pr_merge_done_blocked",
375	        task_id: taskId,
376	        feature_id: featureId,
377	        reason: "commit_failed",
378	        details: String(e),
379	      });
380	      continue;
381	    }
382	
383	    const firstPush = spawnSync(
384	      "git",
385	      ["-C", workspaceRoot, "push", "origin", taskBranch],
386	      { env, encoding: "utf-8" },
387	    );
388	
389	    if (firstPush.status === 0) {
390	      pushSucceeded = true;
391	    } else {
392	      // Push rejected — attempt fetch + rebase recovery.
393	      try {
394	        execSync(`git -C "${workspaceRoot}" fetch origin`, { env, stdio: "pipe" });
395	      } catch (e) {
396	        emit({
397	          type: "pr_merge_done_blocked",
398	          task_id: taskId,
399	          feature_id: featureId,
400	          reason: "fetch_failed_during_push_recovery",
401	          details: String(e),
402	        });
403	        continue;
404	      }
405	
406	      const rebaseResult = spawnSync(
407	        "git",
408	        ["-C", workspaceRoot, "rebase", `origin/${taskBranch}`],
409	        { env, encoding: "utf-8" },
410	      );
411	
412	      if (rebaseResult.status === 0) {
413	        // Clean rebase — retry push.
414	        const retryPush = spawnSync(
415	          "git",
416	          ["-C", workspaceRoot, "push", "origin", taskBranch],
417	          { env, encoding: "utf-8" },
418	        );
419	        if (retryPush.status === 0) {
420	          pushSucceeded = true;
421	        } else {
422	          emit({
423	            type: "pr_merge_done_blocked",
424	            task_id: taskId,
425	            feature_id: featureId,
426	            reason: "push_rejected_after_clean_rebase",
427	            details: retryPush.stderr ?? "",
428	          });
429	          continue;
430	        }
431	      } else {
432	        // Conflicted rebase — spawn Claude to resolve YAML conflict markers.
433	        const conflictedFiles = listConflictedFiles(workspaceRoot, env);
434	        const prompt = buildYamlConflictResolutionPrompt(workspaceRoot, conflictedFiles);
435	
436	        let resolveSucceeded = false;
437	        try {
438	          resolveSucceeded = await invoker(prompt, workspaceRoot, env);
439	        } catch { /* fall through to block */ }
440	
441	        if (resolveSucceeded) {
442	          execSync(`git -C "${workspaceRoot}" add -A`, { env, stdio: "pipe" });
443	          const continueResult = spawnSync(
444	            "git",
445	            ["-C", workspaceRoot, "rebase", "--continue"],
446	            { env: { ...env, GIT_EDITOR: "true", GIT_SEQUENCE_EDITOR: "true" }, encoding: "utf-8" },
447	          );
448	
449	          if (continueResult.status === 0) {
450	            const finalPush = spawnSync(
451	              "git",
452	              ["-C", workspaceRoot, "push", "origin", taskBranch],
453	              { env, encoding: "utf-8" },
454	            );
455	            if (finalPush.status === 0) {
456	              pushSucceeded = true;
457	            } else {
458	              spawnSync("git", ["-C", workspaceRoot, "rebase", "--abort"], { env, encoding: "utf-8" });
459	              emit({
460	                type: "pr_merge_done_blocked",
461	                task_id: taskId,
462	                feature_id: featureId,
463	                reason: "push_rejected_after_claude_rebase",
464	                details: finalPush.stderr ?? "",
465	              });
466	              continue;
467	            }
468	          } else {
469	            spawnSync("git", ["-C", workspaceRoot, "rebase", "--abort"], { env, encoding: "utf-8" });
470	            emit({
471	              type: "pr_merge_done_blocked",
472	              task_id: taskId,
473	              feature_id: featureId,
474	              reason: "rebase_continue_failed_after_claude_resolve",
475	              details: continueResult.stderr ?? "",
476	            });
477	            continue;
478	          }
479	        } else {
480	          spawnSync("git", ["-C", workspaceRoot, "rebase", "--abort"], { env, encoding: "utf-8" });
481	          emit({
482	            type: "pr_merge_done_blocked",
483	            task_id: taskId,
484	            feature_id: featureId,
485	            reason: "rebase_conflict_unresolvable",
486	            conflicted_files: conflictedFiles,
487	          });
488	          continue;
489	        }
490	      }
491	    }
492	
493	    if (!pushSucceeded) continue;
494	
495	    emit({ type: "task_marked_done", task_id: taskId, feature_id: featureId });
496	
497	    // ── 6. Merge the workspace PR via GitHub REST API ─────────────────────────
498	    if (!task.workspace_pr?.url) {
499	      emit({
500	        type: "workspace_pr_missing_for_merge",
501	        task_id: taskId,
502	        feature_id: featureId,
503	        note: "workspace_pr is null — skipping workspace PR merge. Task YAML still marked done.",
504	      });
505	      continue;
506	    }
507	
508	    const coords = parsePrUrl(task.workspace_pr.url);
509	    if (!coords) {
510	      emit({
511	        type: "workspace_pr_merge_failed",
512	        task_id: taskId,
513	        feature_id: featureId,
514	        details: `Cannot parse workspace_pr.url: ${task.workspace_pr.url}`,
515	      });
516	      continue;
517	    }
518	
519	    const mergeApiResult = mergeWorkspacePrViaApi(
520	      mgmtRepoOwner,
521	      mgmtRepoName,
522	      coords.pullNumber,
523	      githubToken,
524	    );
525	
526	    if (mergeApiResult.success) {
527	      emit({ type: "workspace_pr_merged", task_id: taskId, feature_id: featureId });
528	    } else {
529	      emit({
530	        type: "workspace_pr_merge_failed",
531	        task_id: taskId,
532	        feature_id: featureId,
533	        details: mergeApiResult.details,
534	      });
535	    }
536	  }
537	}
538	
539	// ── Workspace PR recovery ─────────────────────────────────────────────────────
540	
541	export interface HandleWorkspacePrRecoveriesOptions {
542	  recoveries: WorkspacePrRecovery[];
543	  mgmtRepoOwner: string;
544	  mgmtRepoName: string;
545	  githubToken: string;
546	  emit: (event: Record<string, unknown>) => void;
547	}
548	
549	/**
550	 * For each done task whose workspace PR was not merged (detected by the poll loop),
551	 * retry the merge via the GitHub REST API.
552	 *
553	 * Idempotent: if the PR is already merged, GitHub returns a non-success response
554	 * which is logged as a warning rather than an error.
555	 */
556	export async function handleWorkspacePrRecoveries(
557	  opts: HandleWorkspacePrRecoveriesOptions,
558	): Promise<void> {
559	  const { recoveries, mgmtRepoOwner, mgmtRepoName, githubToken, emit } = opts;
560	
561	  for (const recovery of recoveries) {
562	    const { taskId, featureId, workspacePrUrl } = recovery;
563	
564	    const coords = parsePrUrl(workspacePrUrl);
565	    if (!coords) {
566	      emit({
567	        type: "workspace_pr_recovery_error",
568	        task_id: taskId,
569	        feature_id: featureId,
570	        details: `Cannot parse workspace_pr URL: ${workspacePrUrl}`,
571	      });
572	      continue;
573	    }
574	
575	    emit({
576	      type: "workspace_pr_recovery_merging",
577	      task_id: taskId,
578	      feature_id: featureId,
579	      workspace_pr_url: workspacePrUrl,
580	    });
581	
582	    const result = mergeWorkspacePrViaApi(
583	      mgmtRepoOwner,
584	      mgmtRepoName,
585	      coords.pullNumber,
586	      githubToken,
587	    );
588	
589	    if (result.success) {
590	      emit({ type: "workspace_pr_recovery_merged", task_id: taskId, feature_id: featureId });
591	    } else {
592	      emit({
593	        type: "workspace_pr_recovery_failed",
594	        task_id: taskId,
595	        feature_id: featureId,
596	        details: result.details,
597	      });
598	    }
599	  }
600	}
