1	/**
2	 * Per-cycle in_review PR status poller.
3	 *
4	 * For every `in_review` task across all watched workspaces, calls the GitHub
5	 * GraphQL API to fetch: mergeable state, draft state, and unresolved inline
6	 * review threads.
7	 *
8	 * General PR-level issue comments are intentionally ignored — they are not
9	 * trackable without identity-dependent heuristics and cause dispatch loops.
10	 * Only inline review threads (which have a first-class `isResolved` bit on
11	 * GitHub's side) are used to determine whether a review agent should run.
12	 *
13	 * Pure read — no task YAML mutations.
14	 *
15	 * On API errors, emits `in_review_poll_error` and skips that task.
16	 * Results are passed to the T3 (auto-rebase) and T4 (open-comment) handlers.
17	 */
18	
19	import { existsSync, readFileSync, readdirSync } from "node:fs";
20	import { join } from "node:path";
21	import { spawnSync } from "node:child_process";
22	import { parse as parseYaml } from "yaml";
23	import type { Task } from "../types/task.js";
24	import { featuresRoot, TASKS_DIR, taskBranchName, taskYamlRelPath } from "../paths.js";
25	import { TERMINAL_STATUSES, tryReadTaskFromBranch } from "../task-branch-state.js";
26	
27	// ── Public types ──────────────────────────────────────────────────────────────
28	
29	/**
30	 * A done task found on a feature branch whose workspace PR has not been merged.
31	 * Returned by checkInReviewPrs so the main loop can retry the merge.
32	 */
33	export interface WorkspacePrRecovery {
34	  taskId: string;
35	  featureId: string;
36	  workspaceRoot: string;
37	  /** URL of the management-repo PR that needs to be merged. */
38	  workspacePrUrl: string;
39	}
40	
41	/** Combined result from a single checkInReviewPrs call. */
42	export interface CheckInReviewResult {
43	  /** One entry per successfully-polled in_review task. */
44	  prResults: PrStatusResult[];
45	  /** Done tasks on feature branches whose workspace PR is still open. */
46	  workspacePrRecoveries: WorkspacePrRecovery[];
47	}
48	
49	/** Status reported by the GitHub GraphQL API for a single in_review task's PR. */
50	export interface PrStatusResult {
51	  taskId: string;
52	  featureId: string;
53	  /** Absolute path to the management workspace that owns this task. */
54	  workspaceRoot: string;
55	  /**
56	   * Whether the PR can be cleanly merged into the base branch.
57	   * null means GitHub has not finished computing the mergeability yet.
58	   */
59	  mergeable: boolean | null;
60	  /** True when the PR is in draft state. */
61	  draft: boolean;
62	  /**
63	   * True when the PR has at least one unresolved inline review thread.
64	   * General PR-level issue comments are not tracked.
65	   * This is the trigger for dispatching the respond-to-review agent.
66	   */
67	  hasOpenComments: boolean;
68	  /** True when the PR has been merged into the base branch. */
69	  merged: boolean;
70	}
71	
72	export interface CheckInReviewPrsOptions {
73	  /** Absolute paths to management workspace repos to scan. */
74	  workspaceRoots: string[];
75	  /** GitHub personal access token for API authentication. */
76	  githubToken: string;
77	  emit: (event: Record<string, unknown>) => void;
78	}
79	
80	// ── Internal helpers ──────────────────────────────────────────────────────────
81	
82	/**
83	 * Parse owner, repo, and pull number from a GitHub PR URL.
84	 * Accepts https://github.com/{owner}/{repo}/pull/{number}
85	 * Returns null for any non-matching URL.
86	 */
87	export function parsePrUrl(
88	  url: string,
89	): { owner: string; repo: string; pullNumber: number } | null {
90	  const match = /https?:\/\/github\.com\/([^/]+)\/([^/]+)\/pull\/(\d+)/.exec(url);
91	  if (!match) return null;
92	  return {
93	    owner: match[1],
94	    repo: match[2],
95	    pullNumber: parseInt(match[3], 10),
96	  };
97	}
98	
99	interface GitHubGraphQLPrData {
100	  isDraft: boolean;
101	  merged: boolean;
102	  mergeable: "MERGEABLE" | "CONFLICTING" | "UNKNOWN";
103	  reviewThreads: { nodes: Array<{ isResolved: boolean }> };
104	}
105	
106	interface GitHubGraphQLResponse {
107	  data?: { repository?: { pullRequest?: GitHubGraphQLPrData | null } | null };
108	  errors?: Array<{ message: string }>;
109	}
110	
111	const PR_STATUS_QUERY = `
112	query($owner: String!, $name: String!, $number: Int!) {
113	  repository(owner: $owner, name: $name) {
114	    pullRequest(number: $number) {
115	      isDraft
116	      merged
117	      mergeable
118	      reviewThreads(first: 100) { nodes { isResolved } }
119	    }
120	  }
121	}`.trim();
122	
123	/**
124	 * Call the GitHub GraphQL API via curl to get PR status and unresolved review threads.
125	 * Throws on curl failure, empty response, or GraphQL errors.
126	 */
127	function fetchPrStatus(
128	  owner: string,
129	  repo: string,
130	  pullNumber: number,
131	  githubToken: string,
132	): { draft: boolean; merged: boolean; mergeable: boolean | null; hasOpenComments: boolean } {
133	  const body = JSON.stringify({
134	    query: PR_STATUS_QUERY,
135	    variables: { owner, name: repo, number: pullNumber },
136	  });
137	
138	  const result = spawnSync(
139	    "curl",
140	    [
141	      "-s", "-X", "POST",
142	      "-H", `Authorization: Bearer ${githubToken}`,
143	      "-H", "Content-Type: application/json",
144	      "-H", "Accept: application/vnd.github+json",
145	      "-d", body,
146	      "https://api.github.com/graphql",
147	    ],
148	    { encoding: "utf-8", stdio: ["ignore", "pipe", "pipe"] },
149	  );
150	
