if (githubToken) {
  const prPollIntervalMs =
    (config.pr_poll_interval_seconds ?? config.idle_sleep_seconds ?? 60) * 1000;
  const now = Date.now();

  if (lastPrPollAt === null || now - lastPrPollAt >= prPollIntervalMs) {
    if (pulledWorkspaceRoots.length > 0) lastPrPollAt = now;
    try {
      const { prResults, workspacePrRecoveries } = await checkInReviewPrs({
        workspaceRoots: pulledWorkspaceRoots,
        githubToken,
        emit,
      });

      // ── T3: Auto-rebase for mergeable === false tasks ──────────────────────
      // Run per workspace so the resolver closures have the correct root.
      for (const wsRoot of pulledWorkspaceRoots) {
        const wsResults = prResults.filter((r) => r.workspaceRoot === wsRoot);
        if (wsResults.some((r) => r.mergeable === false)) {
          await handleMergeConflicts({
            prResults: wsResults,
            workspaceRoot: wsRoot,
            resolveImplRepoRoot: (repoId) =>
