            resolveImplBaseBranch: (repoId) =>
              resolveRepoBaseBranch(wsRoot, repoId),
            resolveTaskRepoId: (featureId, taskId) =>
              resolveTaskRepoId(wsRoot, featureId, taskId),
            gitAuthorEmail,
            gitAuthorName,
            sshKeyPath,
            emit,
          });
        }
      }

      // ── T4: Review dispatch for tasks with open comments ──────────────────
      // Run per workspace so the resolver closures have the correct root.
      for (const wsRoot of pulledWorkspaceRoots) {
        const wsResults = prResults.filter((r) => r.workspaceRoot === wsRoot);
        if (wsResults.some((r) => r.hasOpenComments === true)) {
          const wsModelPolicy = loadWorkspaceModelPolicy(wsRoot);
          await handleDraftReviews({
            prResults: wsResults,
            workspaceRoot: wsRoot,
            resolveImplRepoRoot: (repoId) =>
              resolveRepoLocalPath(wsRoot, repoId),
            resolveTaskRepoId: (featureId, taskId) =>
              resolveTaskRepoId(wsRoot, featureId, taskId),
            resolveImplementationModel: (featureId, taskId) => {
              try {
                const tasksMdPath = join(wsRoot, "docs", "features", featureId, "tasks.md");
                const content = readFileSync(tasksMdPath, "utf-8");
                const overrides = parseModelOverrides(content, taskId);
