            gitAuthorEmail,
            gitAuthorName,
            sshKeyPath,
            workflowLocalPath,
            maxTurns: config.budget.max_iterations,
            maxTokens: config.budget.max_tokens_per_task,
            logSinkEnabled: config.log_sink.enabled,
            emit,
          });
        }
      }

      // ── Merge completion for merged implementation PRs ─────────────────────
      // Run per workspace so each handler operates on its own management repo.
      for (const wsRoot of pulledWorkspaceRoots) {
        const wsResults = prResults.filter((r) => r.workspaceRoot === wsRoot);
        if (wsResults.some((r) => r.merged === true)) {
