57	let _ajvValidate: ValidateFunction | null = null;
58	
59	function getValidator(schemaOverride?: object): ValidateFunction {
60	  if (schemaOverride) {
61	    const ajv = new Ajv.default({ allErrors: true });
62	    return ajv.compile(schemaOverride);
63	  }
64	  if (!_ajvValidate) {
65	    const schema = JSON.parse(readFileSync(SCHEMA_PATH, "utf-8"));
66	    const ajv = new Ajv.default({ allErrors: true });
67	    _ajvValidate = ajv.compile(schema);
68	  }
69	  return _ajvValidate;
70	}
