72	function formatAjvErrors(errors: ErrorObject[]): ValidationError[] {
73	  return errors.map((err: ErrorObject) => {
74	    const path = err.instancePath || "/";
75	    let message: string;
76	
77	    switch (err.keyword) {
78	      case "required":
79	        message = `Missing required field: ${err.params.missingProperty}`;
80	        break;
81	      case "additionalProperties":
82	        message = `Unknown field: ${err.params.additionalProperty}`;
83	        break;
84	      case "type":
85	        message = `Expected type "${err.params.type}", got ${typeof err.data}`;
86	        break;
87	      case "minimum":
88	        message = `Value must be >= ${err.params.limit}`;
89	        break;
90	      case "minItems":
91	        message = `Array must have at least ${err.params.limit} item(s)`;
92	        break;
93	      case "minLength":
94	        message = `String must not be empty`;
95	        break;
96	      default:
97	        message = err.message ?? "Validation failed";
98	    }
99	
100	    return { path, message };
101	  });
102	}
