104	/**
105	 * Parse a YAML string and validate it against the agent.yaml schema.
106	 * Returns the validated AgentConfig on success, or structured errors on failure.
107	 */
108	export function validateAgentYaml(
109	  yamlContent: string,
110	  options?: { schema?: object },
111	): ValidationResult {
112	  let data: unknown;
113	  try {
114	    data = parseYaml(yamlContent);
115	  } catch (e) {
116	    return {
117	      valid: false,
118	      errors: [{ path: "/", message: `YAML parse error: ${(e as Error).message}` }],
119	    };
120	  }
121	
122	  if (data === null || data === undefined || typeof data !== "object") {
123	    return {
124	      valid: false,
125	      errors: [{ path: "/", message: "Document must be a YAML mapping (object)" }],
126	    };
127	  }
128	
129	  const validate = getValidator(options?.schema);
130	  const isValid = validate(data);
131	
132	  if (!isValid) {
133	    return {
134	      valid: false,
135	      errors: formatAjvErrors(validate.errors ?? []),
136	    };
137	  }
138	
139	  return { valid: true, config: data as AgentConfig };
140	}
