142	/**
143	 * Load and validate an agent.yaml file from disk.
144	 * Throws if the file cannot be read. Returns a ValidationResult.
145	 */
146	export function loadAgentYaml(
147	  filePath: string,
148	  options?: { schema?: object },
149	): ValidationResult {
150	  const content = readFileSync(filePath, "utf-8");
151	  return validateAgentYaml(content, options);
152	}
